ani = FuncAnimation(
    anim_fig, 
    animate, 
    frames=frames_to_anim,
    init_func=init_anim, 
    interval=int(dt * step_ratio * 1000), 
    blit=True,
    repeat=True
)

anim_ax.legend(loc='lower right')
plt.show()
